function activateRealWorkspace(){if(!previewWorkspace)return;transports=[];fleet=[];drivers=[];previewWorkspace=false;const banner=document.querySelector('#demoDataBanner');if(banner)banner.hidden=true;renderTable();renderCards();renderFleet();renderFleetManagement();renderFuelFleet();renderTimeline();renderReports();renderWorkspaceSummary()}
const initials=n=>n.split(' ').map(x=>x[0]).join('');
function renderTable(list=transports.slice(0,4)){
 document.querySelector('#transportTableBody').innerHTML=list.map(t=>`<tr class="transport-row" data-id="${t.id}"><td><strong>${t.id}</strong><small>${t.client}</small></td><td><div class="route-cell"><span class="route-line"><i></i><span></span><i></i></span><div><strong>${t.from}</strong><small>${t.to}</small></div></div></td><td><div class="driver-cell"><span class="mini-avatar">${initials(t.driver)}</span><div><strong>${t.driver}</strong><small>${t.truck}</small></div></div></td><td><div class="progress-wrap"><div class="progress-meta"><span>${t.progress}%</span><span>${t.left}</span></div><div class="progress"><i style="width:${t.progress}%"></i></div></div></td><td><strong>${t.eta.split(',')[0]}</strong><small>${t.eta.split(',')[1]||''}</small></td><td><span class="badge ${t.tone}">${t.status}</span></td><td><button class="more-btn">•••</button></td></tr>`).join('');
 bindRows();
}
function renderCards(){document.querySelector('#transportCards').innerHTML=transports.map(t=>`<article class="panel transport-card transport-row" data-id="${t.id}"><div class="transport-card-head"><div><h3>${t.id}</h3><p>${t.client}</p></div><span class="badge ${t.tone}">${t.status}</span></div><div class="route-display"><div><b>${t.from.split(',')[0]}</b><span>${t.from.split(',')[1]}</span></div><span>···· ✈ ····</span><div><b>${t.to.split(',')[0]}</b><span>${t.to.split(',')[1]}</span></div></div><div class="progress-meta"><span>Postęp ${t.progress}%</span><span>${t.left} do celu</span></div><div class="progress"><i style="width:${t.progress}%"></i></div><div class="card-footer" style="margin-top:14px"><span class="mini-avatar">${initials(t.driver)}</span><div style="margin-left:8px"><b>${t.driver}</b><span style="display:block">${t.truck}</span></div><div style="text-align:right"><span>ETA</span><b style="display:block">${t.eta}</b></div></div></article>`).join('');bindRows()}
function renderFleet(){document.querySelector('#fleetGrid').innerHTML=fleet.map(f=>`<article class="fleet-card"><div class="fleet-card-head"><div><h3>${f.truck}</h3><p>Volvo FH 500</p></div><span class="badge ${f.state==='W trasie'?'green':f.state==='Uwaga'?'red':'amber'} fleet-status">${f.state}</span></div><div class="vehicle-illustration">▰</div><div class="driver-cell"><span class="mini-avatar">${initials(f.driver)}</span><div><strong>${f.driver}</strong><small>Kierowca</small></div></div><div class="fleet-stats"><div><span>Dzisiaj</span><b>${f.km}</b></div><div><span>Prędkość</span><b>${f.speed}</b></div><div><span>GPS</span><b>${f.gps}</b></div></div></article>`).join('')}
function renderFleetManagement(){document.querySelector('#driversCount').textContent=drivers.length;document.querySelector('#vehiclesCount').textContent=fleet.length;document.querySelector('#driversTable').innerHTML=`<div class="management-head"><span>KIEROWCA</span><span>KONTAKT</span><span>PRAWO JAZDY</span><span>STATUS</span><span></span></div>${drivers.map(d=>`<div class="management-row"><div class="entity-cell"><span class="mini-avatar">${initials(d.name)}</span><section><b>${d.name}</b><small>ID: DR-${String(drivers.indexOf(d)+1).padStart(3,'0')}</small></section></div><div><b>${d.phone}</b><small>${d.email||'Brak e-maila'}</small></div><div><b>${d.license}</b><small>ważne do ${d.until}</small></div><span><i class="entity-status ${d.status==='Nieaktywny'?'off':''}"></i>${d.status}</span><button class="more-btn">•••</button></div>`).join('')}`;document.querySelector('#vehiclesTable').innerHTML=`<div class="management-head vehicle-columns"><span>POJAZD</span><span>KIEROWCA</span><span>DANE GPS</span><span>STATUS</span><span></span></div>${fleet.map((f,i)=>`<div class="management-row vehicle-columns"><div class="entity-cell"><span class="vehicle-mini">▰</span><section><b>${f.truck}</b><small>${f.model||'Volvo FH 500'} · ${f.year||'2022'}</small></section></div><div><b>${f.driver}</b><small>${f.driver==='Nie przypisano'?'Wymaga przypisania':'Przypisany kierowca'}</small></div><div><b>${f.gpsConnected===false?'Do podłączenia':'Połączony'}</b><small>${f.gpsConnected===false?'Brak identyfikatora':f.gps}</small></div><span><i class="entity-status ${f.state==='Nieaktywny'?'off':''}"></i>${f.state}</span><button class="more-btn">•••</button></div>`).join('')}`;const select=document.querySelector('#transportForm select[name="driver"]');const selected=select.value;select.innerHTML=`<option>Nie przypisano</option>${drivers.filter(d=>d.status!=='Nieaktywny').map(d=>`<option>${d.name}</option>`).join('')}`;if([...select.options].some(o=>o.value===selected))select.value=selected}
function renderTimelineDemo(){document.querySelector('#timelineRows').innerHTML=fleet.slice(0,4).map((f,i)=>`<div class="timeline-row"><div class="timeline-person"><span class="mini-avatar">${initials(f.driver)}</span><div><strong>${f.driver}</strong><small>${f.truck}</small></div></div><div class="timeline-track"><div class="timeline-job ${['job-blue','job-orange','job-green','job-blue'][i]}" style="left:${[3,18,7,31][i]}%;width:${[54,47,68,49][i]}%"><b>${transports[i].from.split(',')[0]} → ${transports[i].to.split(',')[0]}</b>${transports[i].id}</div></div></div>`).join('')}
function renderReportsDemo(){const t=transports[0];document.querySelector('#reportsWorkspace').innerHTML=`<div class="report-sidebar">${transports.slice(0,4).map((x,i)=>`<div class="report-select ${i===0?'active':''}" data-report="${x.id}"><h4>${x.client}</h4><p>${x.id} · ${x.to}</p><span class="badge ${x.tone==='red'?'amber':'green'}">${x.tone==='red'?'Wymaga sprawdzenia':'Gotowy'}</span></div>`).join('')}</div><div class="email-preview"><span class="eyebrow">WERSJA ROBOCZA WIADOMOŚCI</span><label><span>Do:</span><input value="operations@nordicfreight.se"></label><label><span>Temat:</span><input value="Transport update · ${t.id}"></label><div class="email-body" contenteditable="true">Good morning,<br><br>The vehicle carrying shipment <strong>${t.id}</strong> is currently on the route from ${t.from} to ${t.to}. The vehicle has completed ${t.progress}% of the route and is approximately <strong>${t.left}</strong> from the delivery location.<br><br>Estimated arrival: <strong>${t.eta}</strong>. The delivery remains on schedule. We will inform you if the situation changes.<br><br>Best regards,<br>Logistics Team</div><div class="email-actions"><button class="secondary-btn">Kopiuj treść</button><button class="primary-btn send-draft">Utwórz draft e-mail</button></div></div>`;document.querySelector('.send-draft').onclick=()=>showToast('Draft został przygotowany','Wiadomość oczekuje na wysłanie.')}
function bindRows(){document.querySelectorAll('.transport-row').forEach(row=>row.onclick=()=>openTransport(row.dataset.id))}
function openTransport(id){const t=transports.find(x=>x.id===id);if(!t)return;document.querySelector('#drawerContent').innerHTML=`<div class="drawer-header"><span class="eyebrow">${t.id}</span><h2>${t.client}</h2><p>Aktywny transport · dane z aplikacji GPS</p></div><span class="badge ${t.tone}">${t.status}</span><div class="drawer-route"><div><i></i><section><small>ZAŁADUNEK</small><b>${t.from}</b></section></div><span></span><div><i></i><section><small>ROZŁADUNEK</small><b>${t.to}</b></section></div></div><div class="drawer-section"><h3>Realizacja</h3><div class="progress-meta"><span>${t.progress}% trasy</span><span>${t.left} do celu</span></div><div class="progress"><i style="width:${t.progress}%"></i></div></div><div class="drawer-section"><h3>Zasoby</h3><div class="drawer-grid"><div><span>Kierowca</span><b>${t.driver}</b></div><div><span>Ciągnik</span><b>${t.truck}</b></div><div><span>Naczepa</span><b>N-${Math.ceil(Math.random()*20).toString().padStart(2,'0')}</b></div><div><span>Planowane ETA</span><b>${t.eta}</b></div></div></div><div class="drawer-section"><h3>Ostatnia pozycja GPS</h3><p>Okolice Jönköping, E4 · zaktualizowano 2 min temu</p></div><button class="primary-btn full">Przygotuj raport dla klienta</button>`;document.querySelector('#detailDrawer').classList.add('open');document.querySelector('#drawerBackdrop').classList.add('open')}
function closeDrawer(){document.querySelector('#detailDrawer').classList.remove('open');document.querySelector('#drawerBackdrop').classList.remove('open')}
const titles={dashboard:'Dzień dobry, Marek',transports:'Transporty',planner:'Planer tras',fleet:'Flota i kierowcy',reports:'Raporty',inbox:'Skrzynka zleceń',kilometers:'Kilometry',fuel:'Paliwo i marża',settlements:'Rozliczenia',settings:'Ustawienia'};
function getSessionUser(){try{return JSON.parse(sessionStorage.getItem('lm_session')||localStorage.getItem('lm_session')||'null')}catch{return null}}
function switchView(name){document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.querySelector(`#${name}View`)?.classList.add('active');document.querySelectorAll('.nav-item').forEach(n=>n.classList.toggle('active',n.dataset.view===name));const sessionUser=getSessionUser();document.querySelector('#pageTitle').textContent=name==='dashboard'?`Dzień dobry, ${sessionUser?.firstName||'Marek'}`:(titles[name]||'Logistic Master');document.querySelector('#sidebar').classList.remove('open');window.scrollTo({top:0,behavior:'smooth'})}
document.querySelectorAll('.nav-item').forEach(n=>n.onclick=()=>switchView(n.dataset.view));document.querySelectorAll('[data-view-jump]').forEach(n=>n.onclick=()=>switchView(n.dataset.viewJump));
