document.querySelector('#analyzeEmailBtn').onclick=()=>{const source=document.querySelector('#emailSource').value.trim();if(!source){showToast('Brakuje treści wiadomości','Wklej maila, który mamy przeanalizować.');return}const btn=document.querySelector('#analyzeEmailBtn');btn.disabled=true;btn.textContent='✦ Analizuję…';setTimeout(()=>{const form=document.querySelector('#transportForm');form.elements.number.value='NF-84721';form.elements.client.value='Nordic Freight AB';form.elements.from.value='Malmö, SE';form.elements.to.value='Oslo, NO';form.elements.date.value='2026-07-21T18:30';form.elements.notes.value='Załadunek 08:00–09:00 · 24 palety · 18 400 kg · wymagany raport poranny';document.querySelectorAll('.confidence').forEach(c=>{c.classList.add('show');const medium=c.dataset.confidence==='notes';c.classList.add(medium?'medium':'high');c.textContent=medium?'82% — sprawdź':'98% pewności';c.closest('label').classList.toggle('field-highlight',medium)});document.querySelector('#extractionResult').classList.add('show');aiPanel.classList.remove('open');btn.disabled=false;btn.textContent='✦ Analizuj wiadomość';showToast('AI odczytało zlecenie','Sprawdź uzupełnione pola przed zatwierdzeniem.');},850)};
document.querySelector('#transportForm').onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.target));activateRealWorkspace();transports.unshift({id:d.number,client:d.client,from:d.from,to:d.to,driver:d.driver,truck:'Do przypisania',progress:0,left:'—',eta:d.date.replace('T',' '),status:'Nowy',tone:'green'});saveWorkspace();renderTable();renderCards();renderWorkspaceSummary();modal.classList.remove('open');showToast('Transport został utworzony',`${d.number} dodano do planera.`);e.target.reset()};
document.querySelectorAll('[data-fleet-tab]').forEach(b=>b.onclick=()=>{document.querySelectorAll('[data-fleet-tab]').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.fleet-subview').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.querySelector(`#fleet${b.dataset.fleetTab[0].toUpperCase()+b.dataset.fleetTab.slice(1)}`).classList.add('active')});
const driverModal=document.querySelector('#driverModal'),vehicleModal=document.querySelector('#vehicleModal');document.querySelector('#addDriverBtn').onclick=()=>driverModal.classList.add('open');document.querySelector('#addVehicleBtn').onclick=()=>vehicleModal.classList.add('open');document.querySelectorAll('[data-close-driver]').forEach(b=>b.onclick=()=>driverModal.classList.remove('open'));document.querySelectorAll('[data-close-vehicle]').forEach(b=>b.onclick=()=>vehicleModal.classList.remove('open'));
document.querySelector('#driverForm').onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));activateRealWorkspace();drivers.push({name:`${d.firstName.trim()} ${d.lastName.trim()}`,phone:d.phone,email:d.email,license:d.license,until:d.licenseUntil,status:d.status});saveWorkspace();renderFleetManagement();renderWorkspaceSummary();driverModal.classList.remove('open');e.currentTarget.reset();showToast('Kierowca został dodany','Jest już dostępny przy przypisywaniu transportów.')};
document.querySelector('#vehicleForm').onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));activateRealWorkspace();fleet.push({truck:d.truck.toUpperCase(),driver:'Nie przypisano',state:'Dostępny',km:'0 km',speed:'0 km/h',gps:d.gps==='Połączony'?'przed chwilą':'Brak',gpsConnected:d.gps==='Połączony',model:d.model,year:d.year,vin:d.vin,type:d.type});saveWorkspace();renderFleet();renderFleetManagement();renderFuelFleet();renderWorkspaceSummary();vehicleModal.classList.remove('open');e.currentTarget.reset();showToast('Pojazd został dodany','Dodano go do struktury floty.')};
document.querySelector('#drawerClose').onclick=closeDrawer;document.querySelector('#drawerBackdrop').onclick=closeDrawer;
document.querySelectorAll('.preview-report').forEach(x=>x.onclick=()=>{switchView('reports')});
document.querySelectorAll('.segmented button').forEach(b=>b.onclick=()=>{document.querySelectorAll('.segmented button').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderTable(b.textContent.includes('uwagi')?transports.filter(t=>t.tone==='red'||t.tone==='amber'):transports.slice(0,4))});
document.querySelector('[data-target]').onclick=()=>document.querySelector('#attentionSection').scrollIntoView({behavior:'smooth'});
document.querySelectorAll('.truck-pin').forEach(p=>p.onclick=()=>showToast(p.dataset.truck,'Pozycja zaktualizowana 2 min temu.'));
