function showToast(title,msg){const t=document.querySelector('#toast');t.querySelector('b').textContent=title;t.querySelector('p').textContent=msg;t.classList.add('show');setTimeout(()=>t.classList.remove('show'),3200)}
function loadUserSession(){const raw=sessionStorage.getItem('lm_session')||localStorage.getItem('lm_session');if(!raw)return;try{const user=JSON.parse(raw);const fullName=`${user.firstName||''} ${user.lastName||''}`.trim();if(fullName){document.querySelector('#userName').textContent=fullName;document.querySelector('#userAvatar').textContent=`${user.firstName?.[0]||''}${user.lastName?.[0]||''}`.toUpperCase();document.querySelector('#pageTitle').textContent=`Dzień dobry, ${user.firstName}`;}document.querySelector('#userRole').textContent=user.role||'Użytkownik'}catch{localStorage.removeItem('lm_session');sessionStorage.removeItem('lm_session')}}
